# List of all books with flag1, flag2, flag3
def list_by_flags_page(request):
    current_user = request.user
    if 'user' in request.session:
        current_user = request.session['user']
    if not current_user.is_authenticated:
        return HttpResponseRedirect('/login')
    if request.method == 'GET':
        template = get_template('list_page.html')
        flag1 = request.GET.get('flag1', None)
        flag2 = request.GET.get('flag2', None)
        flag3 = request.GET.get('flag3', None)
        bool1 = True if flag1 == 'true' else False
        bool2 = True if flag2 == 'true' else False
        bool3 = True if flag3 == 'true' else False
        if not bool1 and not bool2 and not bool3:
            return HttpResponseRedirect('/')
        q_objects = Q(user=request.user)
        if bool1:
            q_objects &= Q(check1=True)
        if bool2:
            q_objects &= Q(check2=True)
        if bool3:
            q_objects &= Q(check3=True)
        records = BookRecord.objects.filter(q_objects)
        variables = {
            'ratings': [2, 4, 6, 8, 10],
            'records': records,
            'user': current_user,
            'list_title': "Books with flags",
        }
        output = template.render(variables)
        return HttpResponse(output)
    return HttpResponseRedirect('/')


def delete_page(request):
    current_user = request.user
    if 'user' in request.session:
        current_user = request.session['user']
    if not current_user.is_authenticated:
        return HttpResponseRedirect('/login')
    if request.method == 'GET':
        form = BookSaveForm(request.GET)
        if form.is_valid():
            try:
                book = Book.objects.get(
                    isbn=form.cleaned_data['isbn']
                )
                record = BookRecord.objects.get(
                    user=request.user,
                    book=book
                )
                record.delete()
            except ObjectDoesNotExist:
                pass
            return HttpResponseRedirect('/')
        else:
            return HttpResponseRedirect('/')
    return HttpResponseRedirect('/')


def user_page(_, username):
    try:
        user = User.objects.get(username=username)
    except Exception:
        raise Http404(f'Cannot find user {username}')
    records = user.bookrecord_set.all()
    template = get_template('list_page.html')
    variables = {
        'ratings': [2, 4, 6, 8, 10],
        'user': user,
        'records': records,
        'list_title': 'Books edited by ' + username
    }
    output = template.render(variables)
    return HttpResponse(output)


@csrf_exempt
@login_required
def import_page(request):
    if request.method == 'POST' and request.FILES.get('csv_file'):
        csv_file = request.FILES['csv_file']
        data = csv_file.read().decode('utf-8')
        io_string = io.StringIO(data)
        reader = csv.reader(io_string, delimiter=',', quotechar='"')

        for row in reader:
            if len(row) < 8:
                continue

            author, title, publisher, isbn, tag_str, date_start_str, date_end_str, memo = row

            book, _ = Book.objects.get_or_create(isbn=isbn)

            date_start = datetime.strptime(date_start_str, "%Y-%m-%d") if date_start_str else None
            date_end = datetime.strptime(date_end_str, "%Y-%m-%d") if date_end_str else None

            book_record, created = BookRecord.objects.get_or_create(
                user=request.user,
                book=book,
                defaults={
                    'title': title,
                    'author': author,
                    'publisher': publisher,
                    'memo': memo,
                    'dateStart': date_start,
                    'dateEnd': date_end
                }
            )

            if not created:
                book_record.title = title
                book_record.author = author
                book_record.publisher = publisher
                book_record.memo = memo
                book_record.dateStart = date_start
                book_record.dateEnd = date_end
                book_record.save()

            # Handle tags
            tag_str = tag_str.strip('[]')
            tag_names = [tag.strip() for tag in tag_str.split(',')] if tag_str else []

            for tag_name in tag_names:
                if tag_name:
                    tag, _ = Tag.objects.get_or_create(name=tag_name)
                    book_record.tags.add(tag)

        return HttpResponseRedirect('/')

    template = get_template('import_page.html')
    return render(request, 'import_page.html', {'user': request.user})

