# List of all books with flag1, flag2, flag3
def list_by_flags_page(request):
    current_user = request.user
    if 'user' in request.session:
        current_user = request.session['user']
    if not current_user.is_authenticated:
        return HttpResponseRedirect('/login')
    if request.method == 'GET':
        template = get_template('list_page.html')
        flag1 = request.GET.get('flag1', None)
        flag2 = request.GET.get('flag2', None)
        flag3 = request.GET.get('flag3', None)
        bool1 = True if flag1 == 'true' else False
        bool2 = True if flag2 == 'true' else False
        bool3 = True if flag3 == 'true' else False
        if not bool1 and not bool2 and not bool3:
            return HttpResponseRedirect('/')
        q_objects = Q(user=request.user)
        if bool1:
            q_objects &= Q(check1=True)
        if bool2:
            q_objects &= Q(check2=True)
        if bool3:
            q_objects &= Q(check3=True)
        records = BookRecord.objects.filter(q_objects)
        variables = {
            'ratings': [2, 4, 6, 8, 10],
            'records': records,
            'user': current_user,
            'list_title': "Books with flags",
        }
        output = template.render(variables)
        return HttpResponse(output)
    return HttpResponseRedirect('/')


def delete_page(request):
    current_user = request.user
    if 'user' in request.session:
        current_user = request.session['user']
    if not current_user.is_authenticated:
        return HttpResponseRedirect('/login')
    if request.method == 'GET':
        form = BookSaveForm(request.GET)
        if form.is_valid():
            try:
                book = Book.objects.get(
                    isbn=form.cleaned_data['isbn']
                )
                record = BookRecord.objects.get(
                    user=request.user,
                    book=book
                )
                record.delete()
            except ObjectDoesNotExist:
                pass
            return HttpResponseRedirect('/')
        else:
            return HttpResponseRedirect('/')
    return HttpResponseRedirect('/')


def user_page(_, username):
    try:
        user = User.objects.get(username=username)
    except Exception:
        raise Http404(f'Cannot find user {username}')
    records = user.bookrecord_set.all()
    template = get_template('list_page.html')
    variables = {
        'ratings': [2, 4, 6, 8, 10],
        'user': user,
        'records': records,
        'list_title': 'Books edited by ' + username
    }
    output = template.render(variables)
    return HttpResponse(output)


@csrf_exempt
@login_required
def import_page(request):
    if request.method == 'POST' and request.FILES.get('csv_file'):
        csv_file = request.FILES['csv_file']
        data = csv_file.read().decode('utf-8')
        io_string = io.StringIO(data)
        reader = csv.reader(io_string, delimiter=',', quotechar='"')

        for row in reader:
            if len(row) < 8:
                continue

            author, title, publisher, isbn, tag_str, date_start_str, date_end_str, memo = row

            book, _ = Book.objects.get_or_create(isbn=isbn)

            date_start = datetime.strptime(date_start_str, "%Y-%m-%d") if date_start_str else None
            date_end = datetime.strptime(date_end_str, "%Y-%m-%d") if date_end_str else None

            book_record, created = BookRecord.objects.get_or_create(
                user=request.user,
                book=book,
                defaults={
                    'title': title,
                    'author': author,
                    'publisher': publisher,
                    'memo': memo,
                    'dateStart': date_start,
                    'dateEnd': date_end
                }
            )

            if not created:
                book_record.title = title
                book_record.author = author
                book_record.publisher = publisher
                book_record.memo = memo
                book_record.dateStart = date_start
                book_record.dateEnd = date_end
                book_record.save()

            # Handle tags
            tag_str = tag_str.strip('[]')
            tag_names = [tag.strip() for tag in tag_str.split(',')] if tag_str else []

            for tag_name in tag_names:
                if tag_name:
                    tag, _ = Tag.objects.get_or_create(name=tag_name)
                    book_record.tags.add(tag)

        return HttpResponseRedirect('/')

    template = get_template('import_page.html')
    return render(request, 'import_page.html', {'user': request.user})

{% load markdown_extras %}

<script>
let sortAscending = true;

function sortDivsByDate() {
  const $container = $("#container");
  const $divs = $container.children("div");

  const sortedDivs = $divs.sort(function(a, b) {
    const dateA = new Date($(a).data("fdate"));
    const dateB = new Date($(b).data("fdate"));

    return sortAscending ? dateA - dateB : dateB - dateA;
  });

  $container.empty().append(sortedDivs);

  // 토글 정렬 방향
  sortAscending = !sortAscending;

  // 버튼 아이콘 및 텍스트 변경
  const $icon = $("#sort-button .material-icons");
  const $text = $("#sort-button-text");

  if (sortAscending) {
    $icon.text("arrow_upward");
    $text.text("by finish date");
  } else {
    $icon.text("arrow_downward");
    $text.text("by finish date");
  }
}
</script>
<div class="row">
    <div class="col"></div>
    <div class="col-auto mt-2">
        <span class="badge bg-secondary">{{ records|length }} {% if records|length == 1 %}Book{% else %}Books{% endif %}</span>
        <a href="javascript:sortDivsByDate();" id="sort-button">
            <span class="material-icons" style="position: relative; top: 5px;">sort</span>
            <span id="sort-button-text">by finish date</span>
        </a>
    </div>
    <div class="col-auto" style="width:10px;"></div>
</div>
<div id="container">
{% for record in records %}
<div class="card card-frame my-1" data-title="{{record.title}}" data-fdate='{{record.dateEnd|date:"Y-m-d"}}' data-isbn="{{record.book.isbn}}">
  <div class="card-body">
  <div class="row">
<div class="col-auto" style="width:110px;">
  {% if record.book.imageUrl %}
    <img src="{{record.book.imageUrl}}" class="img-fluid shadow"/>
  {% endif %}
  {% if user == record.user %}
    <br/>
    <a href="/edit?isbn={{record.book.isbn}}">
      <button class="btn btn-outline-secondary mt-1 w-100">
        <i class="material-icons">create</i>
      </button>
    </a>
  {% endif %}
</div>
      <div class="book_contents col">
      <p>
          {% if record.author %}{{record.author}}. {% endif %}<em>{{record.title}}.</em> {% if record.publisher %}{{record.publisher}}. {% endif %}{% if record.book.isbn %}ISBN: <a class="isbnlink" href="{{record.book.url}}">{{record.book.isbn}}</a>{% endif %}<br/>
          {% if record.dateStart %}{{record.dateStart|date:"Y-m-d"}} {% endif %}{% if record.dateEnd|date:"Y-m-d" %}~ {{record.dateEnd|date:"Y-m-d"}}<br/>{% endif %}
          {% if record.rating > 0 %}
            {% for i in ratings %}
                {% if i <= record.rating %}
          <span class="material-icons">star</span>
                {% else %}
          <span class="material-icons">star_border</span>
                {% endif %}
            {% endfor %}
          <br/>
          {% endif %}
          {% for tag in record.tags.all %}
          <a href="/listtag/?tag={{tag.name}}"><span>{{tag.name}}</span></a>
          {% endfor %}<br/>
          {% if record.check1 %}<span class="material-icons" style="color:#FFD1DC;">flag</span>{% endif %}
          {% if record.check2 %}<span class="material-icons" style="color:#98FF98;">flag</span>{% endif %}
          {% if record.check3 %}<span class="material-icons" style="color:#AEC6CF;">flag</span>{% endif %}
          </p>
	  {% if record.memo is not None %}<div>{{record.memo|markdownify|safe}}</div>{% endif %}
      </div>
  </div>
  </div>
</div>
{% endfor %}
</div>  <!-- container -->

